stabilizers = [stim.PauliString(s.strip()) for s in stabilizers_str.split(',')]
try:
    tableau = stim.Tableau.from_stabilizers(stabilizers, allow_redundant=True, allow_underconstrained=True)
    circuit = tableau.to_circuit(method="graph_state")

    # Replace RX with H to match baseline unitary behavior (start from |0>)
    new_circuit = stim.Circuit()
    for instruction in circuit:
        if instruction.name == "RX":
            targets = instruction.targets_copy()
            new_circuit.append("H", targets)
        else:
            new_circuit.append(instruction)

    with open("candidate.stim", "w") as f:
        print(new_circuit, file=f)
    print("Candidate generated successfully.")
except Exception as e:
    print(f"Error: {e}")
